import { IMessageComposer } from '@nitrots/nitro-renderer';
export class UpgradeStatComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(statName: string) {
        this._data = [statName];
        console.log(`Packet UpgradeStatComposer sent for stat: ${statName}`);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
